// Processar dados do CC Report
const input = $input.first().json;
let data;

try {
  data = input.body;
  if (!data || typeof data !== 'object') {
    throw new Error('Dados inválidos: esperado objeto com dados do CC Report');
  }
} catch (error) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'cc_report',
    event: 'validation_error',
    message: error.message,
    level: 'error'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'Dados inválidos', details: error.message }
  };
}

// Transformar dados do CC Report
const transformed = {
  ID: data.ID || data.id || '',
  ID_SEED: data.ID_SEED || data.seed || '',
  ID_CC: data.ID_CC || data.cc_id || '',
  CC: data.CC || data.cc || '',
  CC_LABEL: data.CC_LABEL || data.cc_label || '',
  VENCIMENTO: data.VENCIMENTO || data.vencimento || null,
  FORNECEDOR: data.FORNECEDOR || data.fornecedor || '',
  NOME_DESPESA: data.NOME_DESPESA || data.nome_despesa || '',
  SITUACAO: data.SITUACAO || data.situacao || '',
  DATA_PAGAMENTO: data.DATA_PAGAMENTO || data.data_pagamento || null,
  CATEGORIA: data.CATEGORIA || data.categoria || '',
  VALOR: parseFloat(data.VALOR || data.valor || 0),
  TYPE: data.TYPE || data.type || 'DEFAULT'
};

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'data_processed',
  cc: transformed.CC,
  valor: transformed.VALOR,
  level: 'info'
}));

return { transformed };

// Sucesso
const result = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'upsert_success',
  affected_rows: result.affectedRows || 0,
  level: 'info'
}));

return {
  statusCode: 201,
  body: { ok: true, message: 'CC report processed successfully' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not process CC report' }
};
